    const counts = {};
    const firstOccurrence = {};

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            // Count frequency
            counts[char] = (counts[char] || 0) + 1;

            // Record first appearance index
            if (!(char in firstOccurrence)) {
                firstOccurrence[char] = i;
            }
        }
    }

    // Get unique vowels present in s
    const uniqueVowels = Object.keys(counts);

    // 2. Sorting Vowels based on criteria: 
    // Primary: Frequency (Descending)
    // Secondary: First Appearance Index (Ascending)
    uniqueVowels.sort((v1, v2) => {
        const count1 = counts[v1];
        const count2 = counts[v2];

        // Compare frequencies (Descending: v2 - v1)
        if (count1 !== count2) {
            return count2 - count1;
        }

        // Frequencies are equal, compare first appearance index (Ascending: v1 - v2)
        return firstOccurrence[v1] - firstOccurrence[v2];
    });

    // 3. Construct the Sorted Vowel Sequence
    const sortedVowelSequence = [];
    for (const vowel of uniqueVowels) {
        const count = counts[vowel];
        for (let k = 0; k < count; k++) {
            sortedVowelSequence.push(vowel);
        }
    }

    // 4. Rebuild the String
    let sequenceIndex = 0;
    let result = [];

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            // Replace vowel with the next character from the sorted sequence
            result.push(sortedVowelSequence[sequenceIndex]);
            sequenceIndex++;
        } else {
            // Consonants remain unchanged
            result.push(char);
        }
    }

    return result.join('');
}

